def heltal(inmatning):
  try: 
    int(inmatning)
    return True
  except ValueError:
    return False

def inmatning():
  val = input("Vad vill du göra?\n")
  while not heltal(val):
    print("Nej, det där var inte ett giligt menyval, vänligen försök igen")
    val = input("Vad vill du göra?\n")
  return int(val)        #Nu vet vi att det är ett heltal så då kan vi göra om datatypen

def meny(): 
  """En funktion som skriver ut en meny och frågar användaren om inmatning"""
  print("Meny\n1. Skriv ut en text.\n2. Mata in en text.\n3. Avsluta.") 
  text = "Det var en gång" 
  val = inmatning()
  while val != 3: 
    if val == 1: 
      print(text) 
    elif val == 2: 
      text = input("Varsågod och mata in din text: \n")
    elif val <=0:
      print("För låg siffra, välj en siffra mellan 1 och 3.")
    #Hur skulle du skriva om du även skulle vilja ha en utskrift för tal större än 3?
    val = inmatning() 
  print("Avslutar.")

meny()
